import React, { useState } from 'react';

export default function QuestionDashboard() {
  const [questionType, setQuestionType] = useState('subjective');
  const [questionText, setQuestionText] = useState('');
  const [answerText, setAnswerText] = useState('');
  const [rubricsText, setRubricsText] = useState('');
  const [message, setMessage] = useState('');

  const handleSave = async (e) => {
    e.preventDefault();
    setMessage('');
    try {
      const payload = {
        question: String(questionText),
        answer: questionType === 'subjective' ? String(answerText) : String(rubricsText),
        q_type: questionType
      };

      const resp = await fetch('http://localhost:8000/questions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      const data = await resp.json();
      if (data.status === 'success') {
        setMessage('Saved successfully');
        setQuestionText('');
        setAnswerText('');
        setRubricsText('');
      } else {
        setMessage('Save failed: ' + (data.message || 'unknown'));
      }
    } catch (err) {
      setMessage('Error: ' + err.message);
    }
  };

  return (
    <div className="question-dashboard">
      <h2>Question Upload Dashboard</h2>
      <form onSubmit={handleSave}>
        <div className="form-row">
          <label>Type</label>
          <select value={questionType} onChange={(e) => setQuestionType(e.target.value)}>
            <option value="subjective">Subjective</option>
            <option value="creative">Creative</option>
          </select>
        </div>

        <div className="form-row">
          <label>Question (text)</label>
          <textarea value={questionText} onChange={(e) => setQuestionText(e.target.value)} required />
        </div>

        {questionType === 'subjective' ? (
          <div className="form-row">
            <label>Answer (paragraph)</label>
            <textarea value={answerText} onChange={(e) => setAnswerText(e.target.value)} placeholder="Enter expected paragraph answer" required />
          </div>
        ) : (
          <div className="form-row">
            <label>Rubrics (one per line)</label>
            <textarea value={rubricsText} onChange={(e) => setRubricsText(e.target.value)} placeholder="Enter rubrics, one per line" />
          </div>
        )}

        <button type="submit" className="upload-btn">Save Question</button>
        {message && <div className="info-message">{message}</div>}
      </form>
    </div>
  );
}
